import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Encontrando Mods Confiáveis","description":"Um guia para achar mods para Fabric usando fontes confiáveis.","frontmatter":{"title":"Encontrando Mods Confiáveis","description":"Um guia para achar mods para Fabric usando fontes confiáveis.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/1.21.8/players/finding-mods.md","filePath":"versions/1.21.8/translated/pt_br/players/finding-mods.md","lastUpdated":1760721669000}`);var a={name:`pt_br/1.21.8/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Encontrando Mods Confiáveis <a class="header-anchor" href="#h1" aria-label="Permalink to “Encontrando Mods Confiáveis”">​</a></h1><p>Primeiramente, a confiança é subjetiva, e você sempre deve usar seu próprio julgamento ao baixar mods. No entanto, há algumas coisas que você pode fazer para te ajudar a encontrar mods confiáveis.</p><h2 id="_1-usar-uma-fonte-que-seja-reconhecidamente-confiavel" tabindex="-1">1. Usar uma Fonte que Seja Reconhecidamente Confiável <a class="header-anchor" href="#_1-usar-uma-fonte-que-seja-reconhecidamente-confiavel" aria-label="Permalink to “1. Usar uma Fonte que Seja Reconhecidamente Confiável”">​</a></h2><p>A maioria dos autores publicam seus mods no <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e no CurseForge.</p><p>Estes sites verificam se os mods são o que dizem ser e se não contêm código malicioso. Você também pode denunciar mods maliciosos nestes sites, e eles tomarão providência quanto antes.</p><h2 id="with-others" tabindex="-1">2. Verificar com Outros! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Verificar com Outros!”">​</a></h2><p>Se você estiver baixando um mod por uma fonte não confiável, cheque com outros para ver se já baixaram o mod pelo mesmo local antes e se não tiveram algum problema com ele.</p><p>Em caso de dúvidas, sinta-se à vontade para perguntar no <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p><h2 id="avoid-malware" tabindex="-1">3. Evitar Sites Comuns de Malware! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Evitar Sites Comuns de Malware!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Sites de malware podem não ser óbvios para todos. Se estiver incerto, peça a opinião de outros ou evite este site por completo e use apenas fontes confiáveis, como Modrinth e CurseForge.</p></div><p>Há muitos sites que dizem ter mods para Minecraft, mas, na verdade, são apenas malware. Você deve evitar estes sites a todo custo.</p><p>Você pode usar programas de antivírus e sites como o <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> ou o <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> para verificar os mods baixados. No entanto, não confie apenas nestes métodos, pois às vezes eles também podem estar incorretos.</p><p>Novamente, em caso de dúvidas, sinta-se à vontade para pedir opiniões no <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};